#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <omp.h>

#include "common.h"

#ifdef TIMING
#include "timing.h"
#endif

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

static int do_verify = 0;

static int omp_num_threads = 40;

static struct option long_options[] = {

  {"input", 1, NULL, 'i'},
  {"size", 1, NULL, 's'},
  {"verify", 0, NULL, 'v'},
  {0,0,0,0}
};

static void lud_diagonal(float *m, int matrix_dim, int offset)
{
    int i, j;

    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    // Load the diagonal block into shadow
#pragma omp parallel for private(j)
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[(offset + i)*matrix_dim + offset + j];
        }
    }

    for(i=0; i < BLOCK_SIZE-1; i++) {
#pragma omp barrier
#pragma omp parallel for private(j)
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            if (tx > i) {
                for(j=0; j < i; j++)
                    shadow[tx][i] -= shadow[tx][j]*shadow[j][i];
                shadow[tx][i] /= shadow[i][i];
            }
        }
#pragma omp barrier
#pragma omp parallel for private(j)
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            if (tx > i) {
                for(j=0; j < i+1; j++)
                    shadow[i+1][tx] -= shadow[i+1][j]*shadow[j][tx];
            }
        }
    }

    // Write back the updated diagonal block (except first row)
#pragma omp parallel for
    for(i=1; i < BLOCK_SIZE; i++){
        m[(offset + i)*matrix_dim + offset] = shadow[i][0];
    }
}

static void lud_perimeter(float *m, int matrix_dim, int offset)
{
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int i,j, array_offset;
    int tid;

#pragma omp parallel private(tid,i,j,array_offset)
    {
        tid = omp_get_thread_num();
        if (tid < BLOCK_SIZE) {
            int idx = tid;
            array_offset = offset*matrix_dim+offset;
            for (i=0; i < BLOCK_SIZE/2; i++){
                dia[i][idx]=m[array_offset+idx];
                array_offset += matrix_dim;
            }
            array_offset = offset*matrix_dim+offset;
            for (i=0; i < BLOCK_SIZE; i++) {
                peri_row[i][idx]=m[array_offset+(tid+1)*BLOCK_SIZE+idx];
                array_offset += matrix_dim;
            }
        } else {
            int idx = tid-BLOCK_SIZE;
            array_offset = (offset+BLOCK_SIZE/2)*matrix_dim+offset;
            for (i=BLOCK_SIZE/2; i < BLOCK_SIZE; i++){
                dia[i][idx]=m[array_offset+idx];
                array_offset += matrix_dim;
            }
            array_offset = (offset+(tid+1)*BLOCK_SIZE)*matrix_dim+offset;
            for (i=0; i < BLOCK_SIZE; i++) {
                peri_col[i][idx] = m[array_offset+idx];
                array_offset += matrix_dim;
            }
        }
#pragma omp barrier

        if (tid < BLOCK_SIZE) { 
            int idx=tid;
            for(i=1; i < BLOCK_SIZE; i++){
                for (j=0; j < i; j++)
                    peri_row[i][idx]-=dia[i][j]*peri_row[j][idx];
            }
        } else { 
            int idx=tid - BLOCK_SIZE;
            for(i=0; i < BLOCK_SIZE; i++){
                for(j=0; j < i; j++)
                    peri_col[idx][i]-=peri_col[idx][j]*dia[j][i];
                peri_col[idx][i] /= dia[i][i];
            }
        }
#pragma omp barrier

        if (tid < BLOCK_SIZE) { 
            int idx=tid;
            array_offset = (offset+1)*matrix_dim+offset;
            for(i=1; i < BLOCK_SIZE; i++){
                m[array_offset+(tid+1)*BLOCK_SIZE+idx] = peri_row[i][idx];
                array_offset += matrix_dim;
            }
        } else { 
            int idx=tid - BLOCK_SIZE;
            array_offset = (offset+(tid+1)*BLOCK_SIZE)*matrix_dim+offset;
            for(i=0; i < BLOCK_SIZE; i++){
                m[array_offset+idx] =  peri_col[i][idx];
                array_offset += matrix_dim;
            }
        }
    }
}

static void lud_internal(float *m, int matrix_dim, int offset)
{
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int i;

#pragma omp parallel for collapse(2) private(i)
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int global_row_id = offset + (ty+1)*BLOCK_SIZE;
            int global_col_id = offset + (tx+1)*BLOCK_SIZE;

            peri_row[ty][tx] = m[(offset+ty)*matrix_dim+global_col_id+tx];
            peri_col[ty][tx] = m[(global_row_id+ty)*matrix_dim+offset+tx];
        }
    }

#pragma omp barrier

#pragma omp parallel for collapse(2) private(i)
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            float sum = 0;
            for (i=0; i < BLOCK_SIZE; i++)
                sum += peri_col[ty][i] * peri_row[i][tx];
            int global_row_id = offset + (ty+1)*BLOCK_SIZE;
            int global_col_id = offset + (tx+1)*BLOCK_SIZE;
            m[(global_row_id+ty)*matrix_dim+global_col_id+tx] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i=0;

    for (i=0; i < matrix_dim-BLOCK_SIZE; i += BLOCK_SIZE) {
        lud_diagonal(m, matrix_dim, i);
        lud_perimeter(m, matrix_dim, i);
        int grid_dim = (matrix_dim - i)/BLOCK_SIZE - 1;
#pragma omp parallel for collapse(2) num_threads(omp_num_threads)
        for (int by = 0; by < grid_dim; by++) {
            for (int bx = 0; bx < grid_dim; bx++) {
                lud_internal(m, matrix_dim, i);
            }
        }
    }
    lud_diagonal(m, matrix_dim, i);
}

int
main ( int argc, char *argv[] )
{
  printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);

  int matrix_dim = 32; 
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;

  while ((opt = getopt_long(argc, argv, "::vs:i:", 
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);
      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
	      argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (optind < argc) || (optind == 1)) {
    fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  } 
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }
  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  }

  if (do_verify){
    printf("Before LUD\n");
    matrix_duplicate(m, &mm, matrix_dim);
  }

  stopwatch_start(&sw);

  lud_omp(m, matrix_dim);

  stopwatch_stop(&sw);
  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");
    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim); 
    free(mm);
  }

  free(m);

#ifdef  TIMING
  // Timing prints if needed
#endif

  return EXIT_SUCCESS;
}
